INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-6f0ba476-moex-00600', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '乙公司於X7年初以$420,000購入機器設備，估計耐用年限8年，殘值$15,000，以成本模式衡量， 採年數合計法提列折舊。若 X8 年底發生不利之重大變動，經減損測試，估計該機器設備之使用 價值為$200,000，公允價值減處分成本為$225,000，則X8年應認列之減損損失為：', '["$11,250", "$26,250", "$45,000", "$51,250"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00601', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', 'X3年7月1日甲公司購買乙公司北區事業部，北區事業部下有A生產線與B生產線，而上述二 生產線均為獨立的現金產生單位，購買時共支付$480,000 千元，A、B 二生產線之公允價值各為 $250,000 千元與$150,000 千元。X3 年底 A 生產線有減損跡象，A、B 生產線可回收金額各為 $180,000千元與$150,000千元，A、B生產線之帳面金額各為$220,000千元與$120,000千元（不 包括商譽），假設購買時所產生之商譽無法合理分攤至A生產線與B生產線，下列敘述何者錯誤？', '["甲公司購買乙公司北區事業部時，應認列商譽$80,000千元", "X3年底應認列商譽減損損失$170,000千元", "X3年底A生產線商譽以外資產，應認列減損損失$40,000千元", "X3年底B生產線商譽以外資產，毋須認列減損損失"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00602', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司X2年4月1日總共支付$11,000,000購買一辦公大樓，預定作為出租用途以賺取租金。其 中建築物之公允價值為$9,600,000，估計耐用年限50年，無殘值；另土地之公允價值為$2,400,000， 公司採公允價值模式衡量。X2年7月1日起以營業租賃方式出租予丁公司，租期5年，每個月 月初收取租金$40,000。X2年12月31日建築物與土地之公允價值分別為$9,800,000及$2,500,000， 公司折舊政策一律採直線法。試問X2年此項不動產對甲公司的本期損益淨影響為何？', '["本期損益增加$108,000", "本期損益增加$540,000", "本期損益增加$1,408,000", "本期損益增加$1,540,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00603', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年初購買10隻肉豬，每隻售價$8,000，另外共支付運費$2,000及裝卸費$1,000。X1年度 飼養支出共計為$20,000，甲公司於X1年底將10隻肉豬屠宰後出售，售價共計$120,000，另支付運送 到肉品市場的運費$800及市場管理費$800。請問這10隻肉豬轉化之農業產品，應以多少金額衡量？', '["$83,000", "$103,000", "$118,400", "$120,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00604', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', 'X6 年 12 月 31 日丁客運公司的駕駛肇事，丁客運公司評估很有可能必須賠償受害人，而賠償金 額的最佳估計是$2,100,000。幸好丁客運公司有投保第三人責任險，幾乎確定可獲理賠歸墊 $1,800,000。針對上述交易中「理賠歸墊」之會計處理，何者正確？', '["認列應收理賠款", "僅須附註揭露", "認列應付理賠款", "毋須揭露"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00605', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司於X1、X2年底有同一項未決訴訟進行中，甲公司被告侵害他人的專利權，於X1年底委 任律師團評估甲公司敗訴機率為60%，若敗訴，賠償金額為1千萬元。於X2年底委任律師團根 據新事證，重新評估甲公司敗訴機率降為40%，但若不幸敗訴，則賠償金額將提高為2千萬元。 請問有關此項未決訴訟，對甲公司X1及X2年度損益之影響金額分別為何？', '["X1年度淨利降低6百萬元，X2年度淨利降低2百萬元", "X1年度淨利降低1千萬元，X2年度淨利降低1千萬元", "X1年度淨利降低6百萬元，X2年度淨利無影響", "X1年度淨利降低1千萬元，X2年度淨利增加1千萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00606', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司 X1 年底結帳前的保留盈餘及其他權益分別為$20,000,000 及$5,000,000，由甲公司編製完 成的X1年度綜合損益表得知本期淨利$1,200,000、國外營運機構財務報表換算之兌換差額（稅後 淨額）$(500,000)、透過其他綜合損益按公允價值衡量之股票投資未實現評價利益（稅後淨額） $200,000、透過其他綜合損益按公允價值衡量之債券投資未實現評價利益（稅後淨額）$300,000、 透過其他綜合損益按公允價值衡量之債券投資出售利益$100,000。請問甲公司 X1 年底資產負債 表權益項下之「保留盈餘」及「其他權益」金額分別為多少？', '["$21,200,000；$5,000,000", "$21,300,000；$5,100,000", "$21,400,000；$5,200,000", "$21,500,000；$5,300,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00607', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '乙公司於X1年1月1日給予高階管理者30,000股認股權，約定服務滿二年後，得於X3年1月 1日至12月31日按每股$40價格行使認股權，若給與日普通股市價為每股$52，認股權公允價值 為每股$10，既得日普通股市價為每股$50，認股權公允價值為每股$8。乙公司估計二年內高階管 理者喪失認股權比率為20%，乙公司X1年度應認列的勞務成本為：', '["$30,000", "$60,000", "$96,000", "$120,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00608', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '丁公司X1年底存貨與應付帳款之帳面金額分別為$500,000與$720,000，若該公司X2年底存貨之 帳面金額較X1年底增加$60,000、應付帳款之帳面金額較X1年底減少$20,000，X2年度銷貨成本 為$930,000。請問丁公司於X2年度支付給供應商貨款金額為何？', '["$1,010,000", "$1,100,000", "$1,260,000", "$1,170,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00609', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司僅有一筆於X2年12月底向銀行舉借5年期的分期還款負債$129,884需支付利息，有效利 率為5%。此借款從X3年起每年底須償付固定數額$30,000，試問若X4年甲公司所得稅率20%， 稅後淨利為$65,000，則當年度甲公司利息保障倍數為多少？', '["12.22", "13.51", "15.28", "16.28"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
